import React, { useState } from "react";
import "./Login.css";
import bg from "../assets/1stbg.jpg.jpeg";

function Login({ toggleSignup, goForgot, goHome }) {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [message, setMessage] = useState('');

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage('Logging in...');

    try {
      const response = await fetch('http://localhost:5002/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok) {
        setMessage('Login successful!');
        setTimeout(() => goHome(), 500);
      } else {
        setMessage(`Login failed: ${data.message}`);
      }

    } catch (error) {
      setMessage(`Network error: ${error.message}`);
    }
  };

  return (
    <div className="login-container" style={{ backgroundImage: `url(${bg})` }}>
      <div className="login-box">
        <div className="login-header"><h1>LOGIN</h1></div>

        <form className="login-form" onSubmit={handleSubmit}>
          <input type="email" name="email" placeholder="Email" value={formData.email} onChange={handleChange} required />
          <input type="password" name="password" placeholder="Password" value={formData.password} onChange={handleChange} required />

          <p className="forgot" style={{ cursor: 'pointer' }} onClick={goForgot}>
            Forgot password?
          </p>

          <button type="submit">Login</button>

          {message && <p style={{ color: 'white', marginTop: '10px' }}>{message}</p>}

          <p className="signup">
            Don't have an account?{" "}
            <span style={{ cursor: 'pointer', color: 'yellow' }} onClick={toggleSignup}>
              Sign up
            </span>
          </p>
        </form>
      </div>
    </div>
  );
}

export default Login;
